import { useState, useEffect } from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import { Menu, X, Shield, LogIn } from 'lucide-react';

const LINKS = [
  {to:'/',l:'Home'},{to:'/about',l:'About'},{to:'/services',l:'Services'},
  {to:'/blog',l:'Blog'},{to:'/team',l:'Team'},{to:'/announcements',l:'News'},
  {to:'/careers',l:'Careers'},{to:'/contact',l:'Contact'},
];

// Dark navy that matches the hero banner bg (#040b18 / #0d1f3c range)
const NAV_BG        = '#0d1e3a';
const NAV_BG_SCROLL = '#091629';

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  const loc = useLocation();

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', fn, { passive: true });
    fn();
    return () => window.removeEventListener('scroll', fn);
  }, []);

  useEffect(() => { setOpen(false); }, [loc]);
  useEffect(() => {
    document.body.style.overflow = open ? 'hidden' : '';
    return () => { document.body.style.overflow = ''; };
  }, [open]);

  return (
    <>
      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000, height: 64,
        background: scrolled ? NAV_BG_SCROLL : NAV_BG,
        borderBottom: '1px solid rgba(255,255,255,0.08)',
        transition: 'background 0.3s ease',
        boxShadow: scrolled ? '0 2px 24px rgba(0,0,0,0.4)' : 'none',
      }}>
        <div style={{ maxWidth: 1160, margin: '0 auto', padding: '0 20px', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12 }}>

          {/* Logo */}
          <Link to="/" style={{ display: 'flex', flexDirection: 'column', flexShrink: 0, textDecoration: 'none' }}>
            <span style={{ fontFamily: 'var(--serif)', fontSize: '1.25rem', fontWeight: 800, lineHeight: 1, letterSpacing: '-0.02em', color: '#ffffff' }}>SYNNOVIQ</span>
            <span style={{ fontSize: '0.5rem', fontWeight: 700, letterSpacing: '0.22em', textTransform: 'uppercase', marginTop: 2, color: 'rgba(255,255,255,0.45)' }}>Technologies</span>
          </Link>

          {/* Desktop links */}
          <ul style={{ display: 'flex', gap: 2, listStyle: 'none', flex: 1, justifyContent: 'center' }} className="hide-mobile">
            {LINKS.map(({ to, l }) => (
              <li key={to}>
                <NavLink to={to} end={to === '/'} style={({ isActive }) => ({
                  display: 'block', padding: '6px 11px', borderRadius: 6,
                  fontSize: '0.82rem', fontWeight: isActive ? 600 : 400,
                  transition: 'all 0.18s',
                  color: isActive ? '#ffffff' : 'rgba(255,255,255,0.62)',
                  background: isActive ? 'rgba(255,255,255,0.1)' : 'transparent',
                })}
                  onMouseEnter={e => { e.currentTarget.style.color = '#fff'; e.currentTarget.style.background = 'rgba(255,255,255,0.08)'; }}
                  onMouseLeave={e => { e.currentTarget.style.color = ''; e.currentTarget.style.background = ''; }}
                >{l}</NavLink>
              </li>
            ))}
          </ul>

          {/* Desktop actions */}
          <div style={{ display: 'flex', gap: 8, flexShrink: 0 }} className="hide-mobile">
            <Link to="/certificate-verification" style={{
              display: 'flex', alignItems: 'center', gap: 5,
              padding: '7px 13px', borderRadius: 8, fontSize: '0.76rem', fontWeight: 500,
              border: '1px solid rgba(255,255,255,0.2)', color: 'rgba(255,255,255,0.65)',
              transition: 'all 0.18s',
            }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = 'rgba(255,255,255,0.5)'; e.currentTarget.style.color = '#fff'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = 'rgba(255,255,255,0.2)'; e.currentTarget.style.color = 'rgba(255,255,255,0.65)'; }}
            ><Shield size={12} /> Verify</Link>
            <Link to="/login" style={{
              display: 'flex', alignItems: 'center', gap: 6,
              padding: '7px 16px', borderRadius: 8, fontSize: '0.78rem', fontWeight: 600,
              background: '#0057ff', color: '#fff', border: '1px solid #0057ff',
              transition: 'all 0.18s', boxShadow: '0 2px 10px rgba(0,87,255,0.4)',
            }}
              onMouseEnter={e => { e.currentTarget.style.background = '#0044cc'; e.currentTarget.style.borderColor = '#0044cc'; }}
              onMouseLeave={e => { e.currentTarget.style.background = '#0057ff'; e.currentTarget.style.borderColor = '#0057ff'; }}
            ><LogIn size={12} /> Login</Link>
          </div>

          {/* Hamburger — mobile only */}
          <button
            onClick={() => setOpen(!open)}
            className="hide-desktop"
            aria-label={open ? 'Close menu' : 'Open menu'}
            style={{
              width: 40, height: 40, display: 'flex', alignItems: 'center', justifyContent: 'center',
              borderRadius: 8, border: '1px solid rgba(255,255,255,0.22)',
              color: '#fff', background: open ? 'rgba(255,255,255,0.1)' : 'transparent',
              transition: 'background 0.18s',
            }}
          >
            {open ? <X size={18} /> : <Menu size={18} />}
          </button>
        </div>
      </nav>

      {/* Mobile full-screen drawer */}
      <div style={{
        position: 'fixed', inset: 0, zIndex: 999,
        background: '#081120', backdropFilter: 'blur(20px)',
        display: 'flex', flexDirection: 'column',
        padding: '84px 28px 40px',
        transform: open ? 'translateX(0)' : 'translateX(100%)',
        transition: 'transform 0.32s cubic-bezier(0.4,0,0.2,1)',
        overflowY: 'auto',
      }}>
        {LINKS.map(({ to, l }, i) => (
          <NavLink key={to} to={to} end={to === '/'} style={({ isActive }) => ({
            display: 'block', padding: '17px 0',
            fontFamily: 'var(--serif)', fontSize: '1.9rem', fontWeight: 800,
            letterSpacing: '-0.02em', color: isActive ? '#5aa8ff' : '#fff',
            borderBottom: '1px solid rgba(255,255,255,0.07)',
            animationName: 'drawerFadeUp',
            animationDuration: '0.4s',
            animationDelay: `${i * 0.05}s`,
            animationFillMode: 'both',
          })}>{l}</NavLink>
        ))}
        <div style={{ display: 'flex', gap: 12, marginTop: 32 }}>
          <Link to="/certificate-verification" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, padding: '12px', borderRadius: 10, border: '1px solid rgba(255,255,255,0.22)', color: 'rgba(255,255,255,0.75)', fontSize: '0.88rem', fontWeight: 500 }}>
            <Shield size={14} /> Verify
          </Link>
          <Link to="/login" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, padding: '12px', borderRadius: 10, background: '#0057ff', color: '#fff', fontSize: '0.88rem', fontWeight: 600 }}>
            <LogIn size={14} /> Login
          </Link>
        </div>
      </div>

      <style>{`
        @keyframes drawerFadeUp {
          from { opacity: 0; transform: translateY(14px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @media (max-width: 767px)  { .hide-mobile  { display: none !important; } }
        @media (min-width: 768px)  { .hide-desktop { display: none !important; } }
      `}</style>
    </>
  );
}
